import json
b = json.load(open('baseline-packages.json'))
a = json.load(open('after-cpm-packages.json'))

def extract(d):
    pkgs = {}
    for p in d['projects']:
        name = p['path'].split('/')[-1]
        for f in p['frameworks']:
            for pkg in f['topLevelPackages']:
                pkgs[(name, pkg['id'])] = pkg['resolvedVersion']
    return pkgs

bp = extract(b)
ap = extract(a)
if bp == ap:
    print('✅ Package versions are identical — conversion is version-neutral')
else:
    for k in sorted(set(list(bp.keys()) + list(ap.keys()))):
        bv = bp.get(k, 'MISSING')
        av = ap.get(k, 'MISSING')
        if bv != av:
            print(f'CHANGED: {k[0]} {k[1]}: {bv} -> {av}')
